+    /// Clear KV cache for a cell (must be called before cell.reset() to avoid EOG contamination)
+    pub fn clearCellKVCache(self: *Self, cell_id: u32) void {
+        // Clear memory/KV cache for this cell's sequence
+        // This prevents EOG tokens from previous generations from affecting new ones
+        const memory = c.llama_get_memory(self.ctx);
+        if (memory != null) {
+            _ = c.llama_memory_seq_rm(memory, @intCast(cell_id), -1, -1);
+        }
+
+        // Invalidate any prefix cache entries that point to this cell
+        // This is critical because the KV cache now contains generated tokens
+        // which would contaminate future requests using the same prefix
+        var keys_to_remove: std.ArrayListUnmanaged(u64) = .{};
+        defer keys_to_remove.deinit(self.allocator);
+
+        var iter = self.prefix_cache.iterator();
+        while (iter.next()) |entry| {
+            if (entry.value_ptr.cell_id == cell_id) {
+                keys_to_remove.append(self.allocator, entry.key_ptr.*) catch {};
+            }
+        }
+
+        for (keys_to_remove.items) |key| {
+            _ = self.prefix_cache.remove(key);
+        }
+
+        if (keys_to_remove.items.len > 0) {
+            logger.debug("Invalidated {} prefix cache entries for cell {}", .{ keys_to_remove.items.len, cell_id });
+        }
+        logger.debug("Cleared KV cache for cell {}", .{cell_id});
+    }
